// Check SMS delivery result — log failures for visibility
const smsResult = $('Twilio: Send SMS Reply').first().json;
const sid = smsResult?.sid || null;
const errorCode = smsResult?.code || smsResult?.error_code || null;
const errorMessage = smsResult?.message || smsResult?.error_message || null;
const httpStatus = smsResult?.status;

if (errorCode || errorMessage || !sid) {
  console.error('[WF-002] SMS DELIVERY FAILED', JSON.stringify({
    customerPhone: $('Detect Booking Intent').first().json.customerPhone,
    tenantId: $('Detect Booking Intent').first().json.tenantId,
    conversationId: $('Detect Booking Intent').first().json.conversationId,
    errorCode, errorMessage, httpStatus
  }));
}

return [$input.first()];
